// ── COMPANY ICON BADGE ───────────────────────────────────────────────────────
const ICON_MAP = { leaf: Leaf, coffee: Coffee, map: Map, users: Users, home: Home };

function CompanyBadge({ c, size = "lg" }) {
  const isLg = size === "lg";
  const dim = isLg ? 64 : 40;
  const iconSize = isLg ? 28 : 18;
  const IconComponent = ICON_MAP[c.icon] || Leaf;
  return (
    <div style={{
      background: c.primary,
      borderRadius: isLg ? 14 : 10,
      width: dim, height: dim,
      display: "flex", alignItems: "center", justifyContent: "center",
      flexShrink: 0,
      boxShadow: "0 2px 10px rgba(0,0,0,0.22)",
    }}>
      <IconComponent size={iconSize} color="#ffffff" strokeWidth={1.75} />
    </div>
  );
}

