// ── CALCULATOR ───────────────────────────────────────────────────────────────
function Calculator() {
  const [salary, setSalary]               = useState(90000);
  const [users, setUsers]                 = useState(30);
  const [automations, setAutomations]     = useState(8000);
  const [integrations, setIntegrations]   = useState(3000);
  const [boards, setBoards]               = useState(80);
  const [arr, setArr]                     = useState(40000);

  const automationHrs  = (automations * 3 * 0.6) / 60;
  const integrationHrs = (integrations * 6) / 60;
  const boardHrs       = (boards * 20) / 60;
  const reportingHrs   = (automations * 3 * 0.2 + boards * 20 * 0.6 * 5) / 60;
  const collabHrs      = (users * 8 * 0.75 * 0.8 + users * 4 * 0.5) / 60;

  const totalHrs   = Math.round(automationHrs + integrationHrs + boardHrs + reportingHrs + collabHrs);
  const monthlyVal = totalHrs * (salary / 2080);
  const annualVal  = monthlyVal * 12;
  const roi        = arr > 0 ? annualVal / arr : 0;
  const roiDisplay = roi >= 1 ? roi.toFixed(1) + "X" : "<1X";
  const perUser    = users > 0 ? Math.round(totalHrs / users) : 0;
  const roiColor   = roi >= 20 ? "#1a8a1a" : roi >= 10 ? "#ea553c" : roi >= 5 ? WP.amber : WP.grey400;

  const sliders = [
    { label:"Average Annual Salary (AUD)", val:salary, set:setSalary, min:50000, max:250000, step:5000, fmt:(v)=>"$" + v.toLocaleString() },
    { label:"Active Users (Seats)", val:users, set:setUsers, min:5, max:500, step:5, fmt:(v)=>v },
    { label:"Monthly Automations", val:automations, set:setAutomations, min:500, max:100000, step:500, fmt:(v)=>v.toLocaleString() },
    { label:"Monthly Integration Events", val:integrations, set:setIntegrations, min:0, max:50000, step:500, fmt:(v)=>v.toLocaleString() },
    { label:"Total Active Boards", val:boards, set:setBoards, min:5, max:2000, step:10, fmt:(v)=>v },
    { label:"Annual monday.com Investment (AUD)", val:arr, set:setArr, min:5000, max:1000000, step:5000, fmt:(v)=>"$" + v.toLocaleString() },
  ];

  const breakdown = [
    { label:"Automations",    hrs:Math.round(automationHrs),  color:WP.orange },
    { label:"Integrations",   hrs:Math.round(integrationHrs), color:WP.violet },
    { label:"Board Structure",hrs:Math.round(boardHrs),       color:WP.amber },
    { label:"Reporting",      hrs:Math.round(reportingHrs),   color:"#00bcd4" },
    { label:"Collaboration",  hrs:Math.round(collabHrs),      color:WP.pink },
  ];

  return (
    <div style={{ fontFamily:"'Poppins',sans-serif" }}>
      <div style={{ marginBottom:24 }}>
        <h3 style={{ fontFamily:"'Poppins',sans-serif", fontSize:20, fontWeight:700, color:WP.text, margin:"0 0 6px" }}>
          What could monday.com be worth for your team?
        </h3>
        <p style={{ fontSize:13, color:WP.grey400, margin:0, fontFamily:"'Poppins',sans-serif" }}>
          Based on real usage patterns from Work Perfect enterprise customers in Australia. Adjust the inputs to reflect your business.
        </p>
      </div>

      <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:"20px 32px", marginBottom:28 }}>
        {sliders.map(({ label, val, set, min, max, step, fmt }) => (
          <div key={label}>
            <div style={{ display:"flex", justifyContent:"space-between", marginBottom:7 }}>
              <label style={{ fontSize:11.5, fontWeight:600, color:WP.grey700, fontFamily:"'Poppins',sans-serif" }}>{label}</label>
              <span style={{ fontSize:11.5, fontWeight:700, color:WP.orange, fontFamily:"'Poppins',sans-serif" }}>{fmt(val)}</span>
            </div>
            <input type="range" min={min} max={max} step={step} value={val} onChange={e => set(Number(e.target.value))} />
          </div>
        ))}
      </div>

      <div style={{ background:WP.navy, borderRadius:14, padding:"26px 30px" }}>
        <div style={{ height:3, background:"linear-gradient(90deg,#ea553c,#f9ae39)", borderRadius:4, marginBottom:20 }} />
        <div style={{ fontSize:9, fontWeight:700, letterSpacing:2.5, color:"rgba(255,255,255,0.35)", textTransform:"uppercase", marginBottom:14, fontFamily:"'Poppins',sans-serif" }}>
          Your Estimated Return
        </div>
        <div style={{ display:"grid", gridTemplateColumns:"repeat(4,1fr)", gap:12, marginBottom:24 }}>
          {[
            { label:"ROI Multiple", value:roiDisplay, color:roiColor },
            { label:"Monthly Value", value:fmtDollars(monthlyVal), color:WP.white },
            { label:"Annual Value", value:fmtDollars(annualVal), color:WP.white },
            { label:"Staff Value Saved / User / Month", value:fmtDollars(perUser * (salary / 2080)), color:WP.white },
          ].map(({ label, value, color }) => (
            <div key={label} style={{ background:"rgba(255,255,255,0.06)", borderRadius:10, padding:"14px 16px", border:"1px solid rgba(255,255,255,0.08)" }}>
              <div style={{ fontSize:9, fontWeight:600, letterSpacing:1.8, textTransform:"uppercase", color:"rgba(255,255,255,0.35)", marginBottom:6, fontFamily:"'Poppins',sans-serif" }}>{label}</div>
              <div style={{ fontFamily:"'Poppins',sans-serif", fontWeight:800, fontSize:22, color }}>{value}</div>
            </div>
          ))}
        </div>

        <div style={{ borderTop:"1px solid rgba(255,255,255,0.08)", paddingTop:18 }}>
          <div style={{ fontSize:9, color:"rgba(255,255,255,0.3)", letterSpacing:1.5, marginBottom:12, fontFamily:"'Poppins',sans-serif", textTransform:"uppercase" }}>Hours saved by driver (monthly)</div>
          <div style={{ display:"flex", gap:8, flexWrap:"wrap" }}>
            {breakdown.map(({ label, hrs, color }) => (
              <div key={label} style={{ background:"rgba(255,255,255,0.05)", borderRadius:8, padding:"10px 14px", flex:"1 1 110px", borderTop:"2px solid " + color }}>
                <div style={{ fontFamily:"'Poppins',sans-serif", fontWeight:700, fontSize:18, color }}>{hrs.toLocaleString()}</div>
                <div style={{ fontSize:10, color:"rgba(255,255,255,0.35)", marginTop:3, fontFamily:"'Poppins',sans-serif" }}>{label}</div>
              </div>
            ))}
          </div>
        </div>

        <p style={{ fontSize:10.5, color:"rgba(255,255,255,0.18)", margin:"18px 0 0", lineHeight:1.6, fontFamily:"'Poppins',sans-serif" }}>
          Estimates are based on verified customer usage data. Salary assumption: ${salary.toLocaleString()} per year. Hourly rate: ${(salary/2080).toFixed(0)} per hour.
          Methodology mirrors the monday.com Pulse ROI model. Contact Work Perfect for a tailored assessment at workperfect.io
        </p>
      </div>
    </div>
  );
}

